/**
 * Given a sequence of student IDs entering a classroom, where the IDs range from 0 to N-1,
 * calculate the total number of handshakes that occur. Each student will shake hands with 
 * every student already in the classroom who has a smaller ID number. The sequence represents 
 * the order in which students enter the classroom.
 *
 * Examples:
 *    countHandshakes(3, [2, 1, 0])  // returns 0
 */
function countHandshakes(n, order) {
  // Initialize a count variable to keep track of the number of handshakes
  let count = 0;

  // Iterate over the sequence of IDs
  for (let i = 0; i < order.length; i++) {
    // Compare the current ID with all IDs that came before it in the sequence
    for (let j = 0; j < i; j++) {
      // If the current ID is less than the ID that came before it, it represents a handshake
      if (order[i] < order[j]) {
        count++;
      }
    }
  }

  // Return the total number of handshakes
  return count;
}

// Test cases to verify the solution correctness
console.log(countHandshakes(3, [2, 1, 0])); // Expected: 0
console.log(countHandshakes(4, [1, 3, 2, 0])); // Expected: 3
console.log(countHandshakes(5, [0, 4, 1, 3, 2])); // Expected: 6
console.log(countHandshakes(7, [6, 5, 4, 3, 2, 1, 0])); // Expected: 21

