 * connected pixels of the same color to a chosen color, where two pixels are connected if they are 
 * adjacent and have the same color. The goal is to find the minimum number of operations required 
 * to make all pixels the same color.
 * Note: For each color, there are at most 20 pixels of that color.
 * 
 * Examples:
 *    extraNumber(5, [1, 2, 3, 2, 1]) returns 2
 */
function minOperations(n, pixels) {
    let connectedPixels = new Map();
    let colorChangeMap = new Map();
    let minimumOperations = 0;

    for (let i = 0; i < pixels.length; i++) {
        let pixelColor = pixels[i];

        if (connectedPixels.has(pixelColor)) {
            let connectedColors = connectedPixels.get(pixelColor);

            if (colorChangeMap.has(pixelColor)) {
                let colorToChange = colorChangeMap.get(pixelColor);

                if (!connectedColors.has(colorToChange)) {
                    connectedColors.add(colorToChange);
                    connectedPixels.set(pixelColor, connectedColors);
                }
            } else {
                colorChangeMap.set(pixelColor, pixelColor);
                connectedPixels.set(pixelColor, new Set([pixelColor]));
            }
        } else {
            colorChangeMap.set(pixelColor, pixelColor);
            connectedPixels.set(pixelColor, new Set([pixelColor]));
        }
    }

    for (let color of connectedPixels.keys()) {
        if (colorChangeMap.get(color)!== color) {
            let connectedColors = connectedPixels.get(color);
            let colorToChange = colorChangeMap.get(color);

            minimumOperations += connectedColors.size - 1;
        }
    }

    return minimumOperations;
}

